#include <stdio.h>
#include <limits.h>
int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int lengths[K];
    for (int i = 0; i < K; i++) {
        scanf("%d", &lengths[i]);
    }
    int minWands[N + 1] = {0};
    int maxWands[N + 1] = {0};
    for (int i = 1; i <= N; i++) {
        minWands[i] = INT_MAX;
        maxWands[i] = 0;
    }
    for (int i = 1; i <= N; i++) {
        for (int j = 0; j < K; j++) {
            if (i == lengths[j]) {
                minWands[i] = 1;
                maxWands[i] = 1;
            } else if (i > lengths[j]) {
                if (minWands[i - lengths[j]] != INT_MAX) {
                    minWands[i] = (minWands[i] < minWands[i - lengths[j]] + 1) ? minWands[i] : minWands[i - lengths[j]] + 1;
                }
                if (maxWands[i - lengths[j]] != 0) {
                    maxWands[i] = (maxWands[i] > maxWands[i - lengths[j]] + 1) ? maxWands[i] : maxWands[i - lengths[j]] + 1;
                }
            }
        }
    }
    if (minWands[N] == INT_MAX) {
        printf("-1 -1\n");
    } else {
        printf("%d %d\n", minWands[N], maxWands[N]);
    }
    return 0;
}

