import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int K = scanner.nextInt();
        int[] lengths = new int[K];
        for (int i = 0; i < K; i++) {
            lengths[i] = scanner.nextInt();
        }
        int[] minWands = new int[N + 1];
        int[] maxWands = new int[N + 1];
        for (int i = 1; i <= N; i++) {
            minWands[i] = Integer.MAX_VALUE;
            maxWands[i] = 0;
        }
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j < K; j++) {
                if (i == lengths[j]) {
                    minWands[i] = 1;
                    maxWands[i] = 1;
                } else if (i > lengths[j]) {
                    if (minWands[i - lengths[j]] != Integer.MAX_VALUE) {
                        minWands[i] = Math.min(minWands[i], minWands[i - lengths[j]] + 1);
                    }
                    if (maxWands[i - lengths[j]] != 0) {
                        maxWands[i] = Math.max(maxWands[i], maxWands[i - lengths[j]] + 1);
                    }
                }
            }
        }
        if (minWands[N] == Integer.MAX_VALUE) {
            System.out.println("-1 -1");
        } else {
            System.out.println(minWands[N] + " " + maxWands[N]);
        }
    }
}

